+
+		stdin.write("line1");
+		await flush();
+		// Ctrl+J = \n (line feed)
+		stdin.write("\n");
+		await flush();
+		stdin.write("line2");
+		await flush();
+
+		// Should NOT have submitted
+		expect(submitted).toBe("");
+		// Should contain both lines
+		expect(lastFrame()).toContain("line1");
+		expect(lastFrame()).toContain("line2");
+
+		// Now submit with regular Enter
+		stdin.write("\r");
+		await flush();
+		expect(submitted).toBe("line1\nline2");
+	});
